import { useEffect, useRef, useState, useMemo } from 'react';
import { MonitorPlay } from 'lucide-react';

// High-Impact Smart Scaler: Maximizes visibility while maintaining professional 'Golden' proportions
function AutoFitLyrics({ lines, isMaster = false, isLiveBroadcast = false, isClearText = false }) {
  const containerRef = useRef(null);
  const textRef = useRef(null);
  const [fontSize, setFontSize] = useState(20);

  // Standard safe-zone padding (10% all around for High-Impact screens)
  const isHighImpact = isMaster || isLiveBroadcast;
  const paddingClass = isHighImpact ? "px-[10%] py-[10%]" : "p-4";
  const opacityClass = isClearText ? "opacity-0" : "opacity-100";

  useEffect(() => {
    const fit = () => {
      const container = containerRef.current;
      const text = textRef.current;
      if (!container || !text) return;

      // Golden Proportions: Target ~10.5% of height, but shrink-to-fit if required
      const idealGoldenSize = container.clientHeight * 0.105; 
      
      // Available area for the text block (80% width/height for High Impact safe zones)
      const maxW = container.clientWidth * (isHighImpact ? 0.8 : 0.95);
      const maxH = container.clientHeight * (isHighImpact ? 0.8 : 0.9);
      
      // Binary Search: Target idealGoldenSize but shrink if it overflows max area
      let lo = 8, hi = idealGoldenSize, best = 8;
      
      while (lo <= hi) {
        const mid = Math.floor((lo + hi) / 2);
        text.style.fontSize = mid + 'px';
        
        // Measure the block's natural scroll dimensions against available area
        if (text.scrollWidth <= maxW && text.scrollHeight <= maxH) {
          best = mid;
          lo = mid + 1;
        } else {
          hi = mid - 1;
        }
      }
      setFontSize(best);
    };

    const ro = new ResizeObserver(fit);
    if (containerRef.current) ro.observe(containerRef.current);
    fit();
    return () => ro.disconnect();
  }, [lines, isHighImpact]);

  return (
    <div ref={containerRef} className={`absolute inset-0 flex items-center justify-center overflow-hidden transition-opacity duration-300 ${paddingClass} ${opacityClass}`}>
      <div 
         ref={textRef} 
         className="font-black text-white text-center leading-[1.2] drop-shadow-[0_4px_48px_rgba(0,0,0,1)] w-full antialiased" 
         style={{ fontSize: fontSize + 'px' }}
      >
        {lines.map((line, i) => <div key={i}>{line}</div>)}
      </div>
    </div>
  );
}

// FixedLyrics is now just an alias for high-impact AutoFit for backwards compatibility
function FixedLyrics({ lines, isClearText = false }) {
  return <AutoFitLyrics lines={lines} isMaster={true} isClearText={isClearText} />;
}

export default function OutputScreen({ payload, isMaster = false, isLiveBroadcast = false, onStatusUpdate = null, remoteCommand = null }) {
    const videoRef = useRef(null);
    const iframeRef = useRef(null);
    const isMutingReports = useRef(false);
    const lastReportTime = useRef(0);
    const lastReportedPaused = useRef(true);

    // YouTube Follower Tracking State
    const followerTimeRef = useRef(0);
    const followerDurationRef = useRef(0);
    const followerPausedRef = useRef(true);
    const lastSentPauseRef = useRef(null);
    const lastUrlRef = useRef("");

    const isMuted = !isMaster || isLiveBroadcast; // Always mute for viewers and previews
    const lastHandledCommandTs = useRef(0);

    // 1. Reactive Command Handler (Responds to props from ProjectorWindow or App)
    useEffect(() => {
        if (!remoteCommand || remoteCommand.ts === lastHandledCommandTs.current) return;
        lastHandledCommandTs.current = remoteCommand.ts;

        const { command, value, isYoutube, isVimeo } = remoteCommand;
        
        // Mute status reporting briefly to prevent feedback loops during seeking
        isMutingReports.current = true;

        // Handle HTML5 Video
        if (videoRef.current) {
           const v = videoRef.current;
           if (command === 'play') v.play().catch(() => { v.muted = true; v.play().catch(() => {}); });
           if (command === 'pause') v.pause();
           if (command === 'seek') v.currentTime = value;
           if (command === 'volume' && (isMaster || !onStatusUpdate)) {
              v.volume = value;
              if (value > 0) v.muted = false;
              else v.muted = true;
           }
        }

        // Handle YouTube/Vimeo Iframe
        if (iframeRef.current && (isYoutube || isVimeo)) {
           let message = '';
           if (isYoutube) {
              if (command === 'play') message = JSON.stringify({ event: 'command', func: 'playVideo' });
              else if (command === 'pause') message = JSON.stringify({ event: 'command', func: 'pauseVideo' });
              else if (command === 'seek') message = JSON.stringify({ event: 'command', func: 'seekTo', args: [value, true] });
              else if (command === 'volume') message = JSON.stringify({ event: 'command', func: 'setVolume', args: [value * 100] });
           } else if (isVimeo) {
              if (command === 'play') message = JSON.stringify({ method: 'play' });
              else if (command === 'pause') message = JSON.stringify({ method: 'pause' });
              else if (command === 'seek') message = JSON.stringify({ method: 'setCurrentTime', value: value });
              else if (command === 'volume') message = JSON.stringify({ method: 'setVolume', value: value });
           }
           if (message) iframeRef.current.contentWindow?.postMessage(message, '*');
        }

        const timeout = setTimeout(() => { 
            isMutingReports.current = false; 
            // Force status sync immediately after mute period ends to fix Network Viewers missing updates
            if (isMaster && onStatusUpdate && videoRef.current) {
                onStatusUpdate({
                    time: videoRef.current.currentTime,
                    duration: videoRef.current.duration || 0,
                    paused: videoRef.current.paused
                });
            }
        }, 300);
        return () => clearTimeout(timeout);
    }, [remoteCommand, isMaster, onStatusUpdate]);

    // Maintain a live reference to the latest payload to avoid stale closures in the handleMessage event listener
    const payloadRef = useRef(payload);
    useEffect(() => {
        payloadRef.current = payload;
    }, [payload]);

    // 2. Status Polling & Listener for Dashboard (YouTube/Vimeo)
    useEffect(() => {
       if (!onStatusUpdate) return; // Allow both Projector and Followers to listen for iframe ready-signals

       const handleMessage = (event) => {
          if (isMutingReports.current) return;
          try {
             const data = typeof event.data === 'string' ? JSON.parse(event.data) : event.data;
             const freshPayload = payloadRef.current;
             if (data.event === 'infoDelivery' && data.info) {
                const info = data.info;
                                // Track internally for Follower mode sync without depending on React state
                 if (info.currentTime !== undefined) followerTimeRef.current = info.currentTime;
                 if (info.duration !== undefined && info.duration > 0) followerDurationRef.current = info.duration;
                 if (info.playerState !== undefined) followerPausedRef.current = (info.playerState !== 1);
                 
                 // Broadcast status using the persistent refs instead of functional updates
                 // This guarantees duration isn't wiped if a secondary infoDelivery pulse is missing the duration key
                 onStatusUpdate({
                    time: followerTimeRef.current,
                    duration: followerDurationRef.current,
                    paused: followerPausedRef.current,
                    ts: Date.now()
                 });
              }
             if (data.event === 'ready' && iframeRef.current) {
                iframeRef.current.contentWindow?.postMessage(JSON.stringify({ method: 'addEventListener', value: 'playProgress' }), '*');
                iframeRef.current.contentWindow?.postMessage(JSON.stringify({ method: 'addEventListener', value: 'loaded' }), '*');
                
                // Auto-bootstrap playback if we were pushed live in a playing state
                // This defeats the race condition where the 'play' remote command arrives before the iframe is bootstrapped
                if (freshPayload && !freshPayload.isPaused) {
                   const playMsg = JSON.stringify(freshPayload.isVimeo ? { method: 'play' } : { event: 'command', func: 'playVideo' });
                   iframeRef.current.contentWindow?.postMessage(playMsg, '*');
                   
                   // Force Network Followers to physically seek to the Master Playhead instantly on startup!
                   // This prevents Youtube/Vimeo network views from starting at 0:00 and remaining 'slightly out of sync' for 2 seconds.
                   if (freshPayload.currentTime > 0.5 && !isMaster) {
                       const seekMsg = JSON.stringify(freshPayload.isVimeo ? { method: 'setCurrentTime', value: freshPayload.currentTime } : { event: 'command', func: 'seekTo', args: [freshPayload.currentTime, true] });
                       iframeRef.current.contentWindow?.postMessage(seekMsg, '*');
                   }
                   
                   // Restore volume over API once playing (bypasses Chrome Autoplay limitations)
                   if (freshPayload.isVimeo && !isMuted) {
                       const volMsg = JSON.stringify({ method: 'setVolume', value: freshPayload.volume !== undefined ? freshPayload.volume : 1 });
                       setTimeout(() => iframeRef.current?.contentWindow?.postMessage(volMsg, '*'), 500);
                   }
                }
             }
             if (data.event === 'loaded' && data.data && freshPayload?.isVimeo) {
                onStatusUpdate({ duration: data.data.duration });
             }
             if (data.event === 'playProgress' && data.data) {
                onStatusUpdate({ time: data.data.seconds, duration: data.data.duration, paused: false });
             }
          } catch (e) {}
       };

       window.addEventListener('message', handleMessage);
       const poll = setInterval(() => {
          if (iframeRef.current && payloadRef.current?.isYouTube) {
             iframeRef.current.contentWindow?.postMessage(JSON.stringify({ event: 'listening' }), '*');
          }
       }, 1000);

       return () => {
          window.removeEventListener('message', handleMessage);
          clearInterval(poll);
       };
    }, [isMaster, onStatusUpdate, payloadRef.current?.isYouTube]);

    // 3. Status Reporting & Follower Sync Logic
    const reportStatus = () => {
        // Master Mode: Designated component reports status to the system
        if (!onStatusUpdate || !videoRef.current || isMutingReports.current) return;
        if (!isMaster) return; // ONLY the Master acts as the source of truth
        
        const v = videoRef.current;
        const now = Date.now();
        
        // Mask the HTML5 Buffering Phase: 
        // If Dashboard issued PLAY (!payload.isPaused), but the hardware hasn't actually started playing yet (e.g., during onLoadedMetadata), 
        // DO NOT report 'paused: true' back to the dashboard, as this overrides the Play button back to a Pause icon!
        const isTemporarilyBuffering = payload && !payload.isPaused && v.paused && v.currentTime < v.duration;
        const reportedPaused = isTemporarilyBuffering ? false : v.paused;

        // Anti-stutter: Throttle continuous time reports to ~2Hz when playing naturally.
        if (now - lastReportTime.current < 500 && reportedPaused === lastReportedPaused.current) return;
        
        lastReportTime.current = now;
        lastReportedPaused.current = reportedPaused;

        onStatusUpdate({
            time: v.currentTime,
            duration: v.duration || 0,
            paused: reportedPaused,
            volume: v.volume,
            ts: Date.now()
        });
    };

    // Follower Sync Logic: If we are a Follower (Phone or Dashboard), we shadow the Master's playhead
    useEffect(() => {
       // Reset refs ONLY on media change to prevent timeline ghosting
       if (payload?.activeMediaUrl && payload.activeMediaUrl !== lastUrlRef.current) {
           lastUrlRef.current = payload.activeMediaUrl;
           followerTimeRef.current = 0;
           followerDurationRef.current = 0;
       }

       // Don't follow if we are the master
       if (isMaster || !payload) return;

       // 1. HTML5 Local Video Sync
       if (videoRef.current && payload.currentTime !== undefined) {
           const v = videoRef.current;
           
           // Interpolate real-time position based on payload transmission latency
           let targetTime = payload.currentTime + ((Date.now() - (payload.currentTimeTs || Date.now())) / 1000);
           
           const diff = v.currentTime - targetTime;
           const absDiff = Math.abs(diff);
           
           if (absDiff > 0.5) {
               v.currentTime = targetTime;
               v.playbackRate = 1.0;
           } else if (!payload.isPaused) {
               // Soft sync rubber-banding for imperceptible convergence!
               if (absDiff > 0.25) {
                   v.playbackRate = diff > 0 ? 0.85 : 1.15; // Gentle convergence
               } else {
                   v.playbackRate = 1.0;
               }
           }
           
           if (payload.isPaused !== undefined && payload.isPaused !== lastSentPauseRef.current) {
              lastSentPauseRef.current = payload.isPaused;
              if (payload.isPaused && !v.paused) {
                 v.pause();
                 v.playbackRate = 1.0;
              } else if (!payload.isPaused && v.paused) {
                 v.play().catch(() => {});
              }
           }
       }
       
       // 2. YouTube / Vimeo External Iframe Sync
       if (iframeRef.current && (payload.isYouTube || payload.isVimeo) && payload.currentTime !== undefined) {
           // Fall back to pure absolute network payload timestamp without Date.now() time-drift calculations
           let targetTime = payload.currentTime + ((Date.now() - (payload.currentTimeTs || Date.now())) / 1000);

           // Enforce time sync if drifted more than 2 seconds (YouTube doesn't support playback rate tuning easily through postMessage API)
           const diff = Math.abs(followerTimeRef.current - targetTime);
           if (diff > 2.0) {
              const msg = JSON.stringify({ event: 'command', func: 'seekTo', args: [targetTime, true] });
              iframeRef.current.contentWindow?.postMessage(msg, '*');
              followerTimeRef.current = targetTime; // Optimistic update to prevent seek looping
           }
           
           // Enforce Play/Pause State with API throttle to completely eliminate Youtube/Vimeo lag
           if (payload.isPaused !== undefined && payload.isPaused !== lastSentPauseRef.current) {
              lastSentPauseRef.current = payload.isPaused;
              const msg = JSON.stringify(
                 payload.isVimeo ? { method: payload.isPaused ? 'pause' : 'play' }
                                 : { event: 'command', func: payload.isPaused ? 'pauseVideo' : 'playVideo' }
              );
              iframeRef.current.contentWindow?.postMessage(msg, '*');
           }
       }
    }, [isMaster, payload?.currentTime, payload?.isPaused]);

    // Display Guard: Determine if we should show live content or standby
    const isNetworkViewer = payload?.isNetworkViewer; // Set in App.jsx network broadcast
    const isDashboardPreview = !isMaster && !isNetworkViewer;
    const shouldShowLiveContent = payload?.isLive || isDashboardPreview || payload?.isBlackScreen || payload?.isShowLogo;

    if (!payload || !shouldShowLiveContent) {
       return (
         <div className="w-full h-full bg-black flex flex-col items-center justify-center p-12 text-center animate-in fade-in duration-700 select-none">
           <div className="relative group">
              <div className="absolute inset-0 bg-blue-600/30 blur-[120px] rounded-full animate-pulse transition-all duration-1000" />
              <h1 className="text-[12cqw] font-black tracking-[0.2em] text-white uppercase relative z-10 drop-shadow-[0_0_30px_rgba(59,130,246,0.3)]">
                 Halos
              </h1>
           </div>
           
           <div className="mt-12 flex flex-col items-center gap-6">
              <div className="flex items-center gap-4 bg-white/10 px-8 py-4 rounded-2xl border-2 border-white/20 backdrop-blur-md shadow-2xl">
                 <div className="w-3 h-3 rounded-full bg-blue-400 animate-ping" />
                 <span className="text-sm font-black uppercase tracking-[0.5em] text-white">Projector Connected</span>
              </div>
              <p className="text-neutral-400 font-bold uppercase tracking-[0.3em] text-xs">Waiting for live content...</p>
           </div>
         </div>
       );
    }
  
    return (
      <div className="w-full h-full bg-black overflow-hidden relative font-sans">
         {!payload?.isBlackScreen && !payload?.isShowLogo && (
            (payload?.activeSlide?.length > 0 || payload?.activeMediaUrl) ? (
               <>
                  {(payload.mediaType === 'image' || payload.mediaType === 'slide_deck') && payload.activeMediaUrl && (
                     <img src={payload.activeMediaUrl} className="w-full h-full object-contain animate-in fade-in duration-500 pointer-events-none" />
                  )}
                  {payload.mediaType === 'video' && payload.activeMediaUrl && (
                     (payload.isYouTube || payload.isVimeo) ? (
                       <iframe 
                         ref={iframeRef}
                         // Force muted=1 on initial load if we want autoplay OR if it's Vimeo (Vimeo strictly blocks script-driven play unless initially muted)
                         src={`${payload.activeMediaUrl}${payload.activeMediaUrl?.includes('?') ? '&' : '?'}autoplay=${payload.itemAutoPlay ? 1 : 0}&enablejsapi=1&api=1&controls=0&mute=${isMuted ? 1 : 0}&muted=${(isMuted || payload.isVimeo) ? 1 : (payload.itemAutoPlay ? 1 : 0)}`} 
                         className="w-full h-full rounded-lg pointer-events-none" 
                         frameBorder="0" 
                         allow={`autoplay; fullscreen; picture-in-picture; encrypted-media`}
                         allowFullScreen
                       />
                     ) : (
                       <video 
                         ref={videoRef}
                         src={payload.activeMediaUrl} 
                         autoPlay={payload.itemAutoPlay}
                         muted={isMuted} 
                         loop 
                         onTimeUpdate={reportStatus}
                         onPlay={reportStatus}
                         onPause={reportStatus}
                         onLoadedMetadata={(e) => {
                             reportStatus();
                             if (!isMaster && payload?.currentTime !== undefined) {
                                 e.target.currentTime = payload.currentTime;
                                 if (payload.isPaused) e.target.pause();
                             }
                         }}
                         onLoadedData={reportStatus}
                         onDurationChange={reportStatus}
                         className="w-full h-full object-contain animate-in fade-in duration-500 pointer-events-none" 
                       />
                     )
                  )}
                  {payload.activeSlide && payload.activeSlide.length > 0 && (
                     (isMaster || isLiveBroadcast)
                        ? <FixedLyrics lines={payload.activeSlide} linesPerSlide={payload.linesPerSlide} isClearText={payload.isClearText} />
                        : <AutoFitLyrics lines={payload.activeSlide} isClearText={payload.isClearText} />
                  )}
               </>
            ) : (
               /* Standby / Holding Screen (Mirrored across Projector and Live Viewer) */
               <div className="flex flex-col items-center justify-center text-center animate-in fade-in duration-1000 w-full h-full bg-black">
                  <div className="relative">
                     <div className="absolute inset-0 bg-blue-600/20 blur-[120px] rounded-full animate-pulse transition-all duration-1000" />
                     <h1 className="text-[12cqw] font-black tracking-[0.2em] text-white uppercase select-none relative z-10 drop-shadow-[0_0_30px_rgba(59,130,246,0.3)]">
                        Halos
                     </h1>
                  </div>
                  <div className="mt-8 flex flex-col items-center gap-4">
                     <div className="flex items-center gap-3 bg-white/5 px-6 py-2.5 rounded-full border border-white/10 backdrop-blur-md">
                        <div className="w-2 h-2 rounded-full bg-blue-400 animate-pulse" />
                        <span className="text-[10px] font-black uppercase tracking-[0.4em] text-white/60">System Standby</span>
                     </div>
                  </div>
               </div>
            )
         )}
         {payload?.isBlackScreen && <div className="absolute inset-0 bg-black z-40" />}
         {payload?.isShowLogo && payload?.logoUrl && !payload?.isBlackScreen && (
            <div className="absolute inset-0 bg-black z-30 flex items-center justify-center">
               <img src={payload.logoUrl} className="w-full h-full object-contain animate-in zoom-in-95" />
            </div>
         )}
      </div>
    );
}
